#include <stdio.h>
#include <string.h>
#include <stdlib.h>

long long binomial(int n, int k) {
    if (k > n - k) k = n - k;
    long long res = 1;
    for (int i = 1; i <= k; ++i) {
        res = res * (n - k + i) / i;
    }
    return res;
}

int main() {
    char line[256];
    if (!fgets(line, sizeof(line), stdin)) return 0;
    int T = atoi(line);
    for (int t = 0; t < T; ++t) {
        if (!fgets(line, sizeof(line), stdin)) break;
        int rowCount, columnCount;
        sscanf(line, "%d %d", &rowCount, &columnCount);
        int down = rowCount - 1;
        int right = columnCount - 1;
        int total = down + right;
        long long ans = binomial(total, down);
        printf("%lld\n", ans);
    }
    return 0;
}

